module SR_FlipFlop (
    input wire S,
    input wire R,
    input wire clk,
    output reg Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (S && ~R) 
            Q <= 1; // set
        else if (~S && R) 
            Q <= 0; // reset
        // else case for S = 0 and R = 0: Hold the state
        // else case for S = 1 and R = 1: Indeterminate, we can keep the previous state
    end
endmodule
